import{_ as e,o as t,c as o,ae as l}from"./chunks/framework.B2m0-DLt.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"note/ai/agent/AI agent面试题.md","filePath":"note/ai/agent/AI agent面试题.md"}'),r={name:"note/ai/agent/AI agent面试题.md"};function i(n,a,h,c,s,d){return t(),o("div",null,[...a[0]||(a[0]=[l('<h2 id="从0到1构建智能体的思路" tabindex="-1">从0到1构建智能体的思路 <a class="header-anchor" href="#从0到1构建智能体的思路" aria-label="Permalink to &quot;从0到1构建智能体的思路&quot;">​</a></h2><h2 id="rag的流程" tabindex="-1">RAG的流程 <a class="header-anchor" href="#rag的流程" aria-label="Permalink to &quot;RAG的流程&quot;">​</a></h2><h2 id="mcp是什么" tabindex="-1">MCP是什么 <a class="header-anchor" href="#mcp是什么" aria-label="Permalink to &quot;MCP是什么&quot;">​</a></h2><h2 id="向量算法了解" tabindex="-1">向量算法了解 <a class="header-anchor" href="#向量算法了解" aria-label="Permalink to &quot;向量算法了解&quot;">​</a></h2><h2 id="如何解决大模型幻觉、回答不准的问题" tabindex="-1">如何解决大模型幻觉、回答不准的问题 <a class="header-anchor" href="#如何解决大模型幻觉、回答不准的问题" aria-label="Permalink to &quot;如何解决大模型幻觉、回答不准的问题&quot;">​</a></h2><h2 id="如何保证大模型按指定格式输出" tabindex="-1">如何保证大模型按指定格式输出 <a class="header-anchor" href="#如何保证大模型按指定格式输出" aria-label="Permalink to &quot;如何保证大模型按指定格式输出&quot;">​</a></h2><h2 id="使用的ai编辑器" tabindex="-1">使用的AI编辑器 <a class="header-anchor" href="#使用的ai编辑器" aria-label="Permalink to &quot;使用的AI编辑器&quot;">​</a></h2><h2 id="openclaw-相关知识" tabindex="-1">OpenClaw 相关知识 <a class="header-anchor" href="#openclaw-相关知识" aria-label="Permalink to &quot;OpenClaw 相关知识&quot;">​</a></h2><h2 id="国内外大模型区别和看法" tabindex="-1">国内外大模型区别和看法 <a class="header-anchor" href="#国内外大模型区别和看法" aria-label="Permalink to &quot;国内外大模型区别和看法&quot;">​</a></h2><h2 id="日常获取ai资讯的渠道" tabindex="-1">日常获取AI资讯的渠道 <a class="header-anchor" href="#日常获取ai资讯的渠道" aria-label="Permalink to &quot;日常获取AI资讯的渠道&quot;">​</a></h2><ul><li>一手资讯，国外的推特 follow 一些相关账号，比如 claude code 、openai、cursor、google ai 、grok等</li><li>微信公众号关注研究AI方向的大佬，AI交流群</li><li>观看AI相关的视频，比如youtube、bilibili等</li></ul><h2 id="如何实现动态加载tools-且不破坏kv-cache缓存" tabindex="-1">如何实现动态加载tools，且不破坏kv cache缓存 <a class="header-anchor" href="#如何实现动态加载tools-且不破坏kv-cache缓存" aria-label="Permalink to &quot;如何实现动态加载tools，且不破坏kv cache缓存&quot;">​</a></h2><p>我是这么想的，不用API自带的tools的参数，改用prompt解析的形式，这样就可以随时在消息中添加信息，不会破坏kv cache。 但是面试官需要使用tools参数进行定义，我是一直没想到办法</p><p>除非就是搞一个新的tools来调用动态加载的tools，但是面试官还是觉得不行</p><h2 id="多agent的通信-任务分配-任务阻塞-是互相通信还是单点通信-一个子agent如何拿到另一个子agent的上下文之类的" tabindex="-1">多agent的通信，任务分配，任务阻塞，是互相通信还是单点通信，一个子agent如何拿到另一个子agent的上下文之类的 <a class="header-anchor" href="#多agent的通信-任务分配-任务阻塞-是互相通信还是单点通信-一个子agent如何拿到另一个子agent的上下文之类的" aria-label="Permalink to &quot;多agent的通信，任务分配，任务阻塞，是互相通信还是单点通信，一个子agent如何拿到另一个子agent的上下文之类的&quot;">​</a></h2><h2 id="acp协议-mcp协议-skills之类理解" tabindex="-1">acp协议，mcp协议，skills之类理解 <a class="header-anchor" href="#acp协议-mcp协议-skills之类理解" aria-label="Permalink to &quot;acp协议，mcp协议，skills之类理解&quot;">​</a></h2><h2 id="如何解决google-anthropic-openai之间消息协议不同的问题-用户可能在一个会话中切换另一个模型-这种如何解决" tabindex="-1">如何解决Google，anthropic，openai之间消息协议不同的问题，用户可能在一个会话中切换另一个模型，这种如何解决 <a class="header-anchor" href="#如何解决google-anthropic-openai之间消息协议不同的问题-用户可能在一个会话中切换另一个模型-这种如何解决" aria-label="Permalink to &quot;如何解决Google，anthropic，openai之间消息协议不同的问题，用户可能在一个会话中切换另一个模型，这种如何解决&quot;">​</a></h2><p>之后就是上下文工程，我就讲了我24年写的那个，qm25+jaccard做本地召回+rag进行向量召回+知识图谱进行多跳搜索最后使用rrf进行排序后rerank</p><p>编程的时候 ，经常会遇到 等待审批，然后根据不同的选择再执行嘛。如果在 SSE 的情况下，应该怎么做？除了 sse 发一个 特殊的 event，暂停传输和接受，然后前端用 post 提交对应的数据。还有 其他方案吗？</p><p>断开+轮询。这个不是异步操作嘛，你就把这个异步操作当成一个tools下发，前端读到就去轮询状态这样。不可能一直保持一个长链接的，用户少还好说，用户多内存直接炸了。</p><p>websocket长链接的内存占用是sse的十倍</p><h2 id="langgraph-的实现原理" tabindex="-1">LangGraph 的实现原理 <a class="header-anchor" href="#langgraph-的实现原理" aria-label="Permalink to &quot;LangGraph 的实现原理&quot;">​</a></h2><h2 id="你的问答机器人的准确率如何保证的-能解决幻觉实际方案是什么" tabindex="-1">你的问答机器人的准确率如何保证的，能解决幻觉实际方案是什么 <a class="header-anchor" href="#你的问答机器人的准确率如何保证的-能解决幻觉实际方案是什么" aria-label="Permalink to &quot;你的问答机器人的准确率如何保证的，能解决幻觉实际方案是什么&quot;">​</a></h2><h2 id="为何使用-langgraph-的方案-为什么不用-n8n-dify" tabindex="-1">为何使用 LangGraph 的方案，为什么不用 n8n，dify <a class="header-anchor" href="#为何使用-langgraph-的方案-为什么不用-n8n-dify" aria-label="Permalink to &quot;为何使用 LangGraph 的方案，为什么不用 n8n，dify&quot;">​</a></h2><h2 id="rag-优化" tabindex="-1">RAG 优化 <a class="header-anchor" href="#rag-优化" aria-label="Permalink to &quot;RAG 优化&quot;">​</a></h2><p>传统 RAG 是固定流程：用户问题向量化 -&gt; 相似度检索 → prompt 拼接 -&gt; 生成回答</p><p>想要优化，最主流的方案就是升级为 Agentic RAG。</p><p>它通过 Agent 自主决策，实现动态优化：</p><ol><li>先对复杂问题进行意图理解与拆解，生成多个子问题；</li><li>根据问题类型智能路由，选择向量库检索、互联网搜索、数据库查询或调用工具；</li><li>检索后进行信息融合、重排、去重；</li><li>进入反思环节，自我评估信息是否足够、是否存在冲突或幻觉；</li><li>如果不满足，自动重新构造查询、再次检索，形成多轮迭代；</li><li>最终确认信息充分后，再生成准确、可靠的回答。</li></ol><p>整个过程不是固定流水线，而是 Agent 自主思考、自主纠错的智能闭环。</p><h2 id="rag-进阶" tabindex="-1">RAG 进阶 <a class="header-anchor" href="#rag-进阶" aria-label="Permalink to &quot;RAG 进阶&quot;">​</a></h2><p>Adaptive RAG、Self-RAG、CRAG、Agentic RAG</p>',32)])])}const u=e(r,[["render",i]]);export{g as __pageData,u as default};
